def bigram_encode(text: str) -> dict:
    words = text.lower().split()
    vec = {}
    for w in words:
        vec[w] = vec.get(w, 0) + 1
    for i in range(len(words) - 1):
        bigram = words[i] + "_" + words[i+1]
        vec[bigram] = vec.get(bigram, 0) + 1
    return vec

